proof_block:
// `next_ensures` is `pub open spec fn`, and the schema-assume scaffolding
// above already exposes per-side information about r1.0, r2.0, the post
// netc states, and the sequence lengths of (r1.1)@/(r2.1)@.  The
// remaining work for z3 is to *line up* the conjunctions hidden inside
// the two `next_ensures` instances — each one is a six-way `&&&` whose
// inner `well_typed_events()` is itself a triple `forall` plus a length
// bound.  Below we surface each of those conjuncts as a stand-alone
// assertion (each one is a direct tautology of the form
// `P ==> conjunct(P)` against `next_ensures`'s definition, so Verus
// verifies them by simple unfolding — no `assume` needed).

assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> r1.0 == post1_netc.ok());
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> post1_self_.invariants(&post1_netc.my_end_point())));
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> HostState::next(pre_self_.view(), post1_self_.view(), (r1.1)@.ios)));
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> (r1.1)@.event_seq() == (r1.1)@.ios));
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ((r1.0 || (r1.1)@.sends.len() > 0)
         ==> post1_netc.history() == pre_netc.history() + (r1.1)@.event_seq()));
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.1)@.well_typed_events());

assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> r2.0 == post2_netc.ok());
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> post2_self_.invariants(&post2_netc.my_end_point())));
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> HostState::next(pre_self_.view(), post2_self_.view(), (r2.1)@.ios)));
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> (r2.1)@.event_seq() == (r2.1)@.ios));
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ((r2.0 || (r2.1)@.sends.len() > 0)
         ==> post2_netc.history() == pre_netc.history() + (r2.1)@.event_seq()));
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.1)@.well_typed_events());

// Expand `well_typed_events()` on both sides so that the three element-
// type `forall`s and the `clocks.len() <= 1` bound are present in the
// proof context for both runs simultaneously.  Without this z3 has to
// pick one trigger or the other; with it, both triggers are alive.
assert(
    (r1.1)@.well_typed_events()
    ==> {
        &&& (forall |i: int| 0 <= i < (r1.1)@.recvs.len()
                ==> (#[trigger] (r1.1)@.recvs[i]) is Receive)
        &&& (forall |i: int| 0 <= i < (r1.1)@.clocks.len()
                ==> ((#[trigger] (r1.1)@.clocks[i]) is ReadClock
                     || (r1.1)@.clocks[i] is TimeoutReceive))
        &&& (forall |i: int| 0 <= i < (r1.1)@.sends.len()
                ==> (#[trigger] (r1.1)@.sends[i]) is Send)
        &&& (r1.1)@.clocks.len() <= 1
    });
assert(
    (r2.1)@.well_typed_events()
    ==> {
        &&& (forall |i: int| 0 <= i < (r2.1)@.recvs.len()
                ==> (#[trigger] (r2.1)@.recvs[i]) is Receive)
        &&& (forall |i: int| 0 <= i < (r2.1)@.clocks.len()
                ==> ((#[trigger] (r2.1)@.clocks[i]) is ReadClock
                     || (r2.1)@.clocks[i] is TimeoutReceive))
        &&& (forall |i: int| 0 <= i < (r2.1)@.sends.len()
                ==> (#[trigger] (r2.1)@.sends[i]) is Send)
        &&& (r2.1)@.clocks.len() <= 1
    });

// `NetClient::ok()` is `!(state() is Error)` (open spec).  Surface this
// equivalence for both post-netc's so that the two `r.0 == post.ok()`
// conjuncts can be related to the schema-assume scaffolding's
// `is_Error` flags on the post-netc states.
assert(post1_netc.ok() == !((post1_netc.state())@ is Error));
assert(post2_netc.ok() == !((post2_netc.state())@ is Error));

// `EventResultsView`'s `View` instance is closed but structural: equality
// of view follows from componentwise equality of the four sequences.
// Drag this out as an explicit implication so z3 can read it backwards
// once the components are known equal.
assert forall |a: EventResults, b: EventResults|
    a.recvs =~= b.recvs && a.clocks =~= b.clocks
    && a.sends =~= b.sends && a.ios =~= b.ios
    implies a.view() == b.view() by {
    assert(a.view().recvs =~= b.view().recvs);
    assert(a.view().clocks =~= b.view().clocks);
    assert(a.view().sends =~= b.view().sends);
    assert(a.view().ios =~= b.view().ios);
};

// Same story for `NetClientView` (structural: equal `history` and equal
// `end_point` ==> equal view).
assert forall |a: NetClient, b: NetClient|
    a.history() == b.history() && a.my_end_point() == b.my_end_point()
    implies a.view() == b.view() by {
    // Closed view; the inner fields are closed too.  Verus discharges
    // structural equality of `NetClientView` by congruence on its two
    // fields once they are known equal.
};
